SELECT model_name, focus_length_mm, megapixel_rating, mount_raw
FROM fa_lenses
WHERE focus_length_mm > 50;

SELECT model_name, wd_mm, magnification_value
FROM non_standard_telecentric_lenses
WHERE wd_mm > 100;

SELECT model_name, zoom_method
FROM zoom_lenses
WHERE zoom_method ILIKE '%motor%';

SELECT model_name, spectral_type, wavelength_min_nm, wavelength_max_nm, focus_length_mm
FROM spectral_lenses
WHERE wavelength_max_nm > 1000;

SELECT model_name, megapixel_rating, focus_length_mm, f_no_min, f_no_max
FROM m12_mount_lenses
WHERE megapixel_rating > 5;

SELECT model_name, numerical_aperture
FROM microscope_lenses
WHERE numerical_aperture > 0.3;
